animations.cssText:
@keyframes button-pop { 
  0% { transform: scale(var(--btn-focus-scale,.98)); }
  40% { transform: scale(1.02); }
  100% { transform: scale(1); }
}

@keyframes checkmark { 
  0% { background-position-y: 5px; }
  50% { background-position-y: -2px; }
  100% { background-position-y: 0px; }
}

@keyframes modal-pop { 
  0% { opacity: 0; }
}

@keyframes progress-loading { 
  50% { background-position-x: -115%; }
}

@keyframes radiomark { 
  0% { box-shadow: 0 0 0 12px var(--fallback-b1,oklch(var(--b1)/1)) inset,0 0 0 12px var(--fallback-b1,oklch(var(--b1)/1)) inset; }
  50% { box-shadow: 0 0 0 3px var(--fallback-b1,oklch(var(--b1)/1)) inset,0 0 0 3px var(--fallback-b1,oklch(var(--b1)/1)) inset; }
  100% { box-shadow: 0 0 0 4px var(--fallback-b1,oklch(var(--b1)/1)) inset,0 0 0 4px var(--fallback-b1,oklch(var(--b1)/1)) inset; }
}

@keyframes rating-pop { 
  0% { transform: translateY(-0.125em); }
  40% { transform: translateY(-0.125em); }
  100% { transform: translateY(0px); }
}

@keyframes skeleton { 
  0% { background-position: 150% center; }
  100% { background-position: -50% center; }
}

@keyframes toast-pop { 
  0% { transform: scale(0.9); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes bounce { 
  0%, 100% { transform: translateY(-25%); animation-timing-function: cubic-bezier(0.8, 0, 1, 1); }
  50% { transform: none; animation-timing-function: cubic-bezier(0, 0, 0.2, 1); }
}

@keyframes pulse { 
  50% { opacity: 0.5; }
}

@keyframes slideUp { 
  0% { opacity: 1; transform: translateY(0px) translateX(-50%); }
  100% { opacity: 0; transform: translateY(-90px) translateX(-50%); }
}

@keyframes sliding { 
  0% { transform: translateX(0px); }
  100% { transform: translateX(-50%); }
}

@keyframes progress-frame { 
  0% { --dot-progress: 0%; }
  100% { --dot-progress: 100%; }
}

@keyframes fadeIn { 
  100% { opacity: 1; }
}

@keyframes fadeOut { 
  0% { opacity: 1; }
  100% { opacity: 0; display: none; }
}

@keyframes anim-in { 
  100% { opacity: 0; border-radius: 0px; width: 600px; height: 600px; }
  0% { width: 0px; height: 0px; border-radius: 100%; opacity: 0.2; }
}

@keyframes dash { 
  0% { stroke-dashoffset: 70; }
  50% { stroke-dashoffset: 0; fill: transparent; }
  100% { stroke-dashoffset: 0; fill: rgb(51, 51, 51); }
}

@keyframes slide-left-right { 
  0% { transform: translateX(0px); }
  50% { transform: translateX(-100px); }
  100% { transform: translateX(0px); }
}

@keyframes ar-button-desktop { 
  0% { bottom: -80px; }
  10% { bottom: 24px; }
  90% { bottom: 24px; }
  100% { bottom: -80px; }
}

@keyframes ar-button { 
  0% { grid-template-columns: 0fr auto; }
  12% { grid-template-columns: 1fr auto; }
  88% { grid-template-columns: 1fr auto; }
  100% { grid-template-columns: 0fr auto; }
}

@keyframes ar-button-message { 
  0% { opacity: 0; visibility: hidden; padding-left: 0px; padding-right: 0px; }
  12% { opacity: 1; visibility: visible; padding-left: 20px; padding-right: 48px; }
  88% { opacity: 1; visibility: visible; padding-left: 20px; padding-right: 48px; }
  100% { opacity: 0; visibility: hidden; padding-left: 0px; padding-right: 0px; }
}

@keyframes wheel-pointer-idle { 
  0% { --tw-translate-y: 8px; }
  50% { --tw-translate-y: 4px; }
  100% { --tw-translate-y: 8px; }
}

@keyframes wheel-pointer-wobble { 
  16.65% { --tw-skew-x: -12deg; }
  33.3% { --tw-skew-x: 10deg; }
  49.95% { --tw-skew-x: -6deg; }
  66.6% { --tw-skew-x: 4deg; }
  83.25% { --tw-skew-x: -2deg; }
  100% { --tw-skew-x: 0; }
}

@keyframes gradient-etc { 
  0% { background-position: 0px 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0px 50%; }
}

@keyframes slideDown { 
  0% { opacity: 0; transform: translateY(-90px) translateX(-50%); }
  100% { opacity: 1; transform: translateY(0px) translateX(-50%); }
}

@keyframes swal2-show { 
  0% { transform: translate3d(0px, -50px, 0px) scale(0.9); opacity: 0; }
  100% { transform: translate3d(0px, 0px, 0px) scale(1); opacity: 1; }
}

@keyframes swal2-hide { 
  0% { transform: translate3d(0px, 0px, 0px) scale(1); opacity: 1; }
  100% { transform: translate3d(0px, -50px, 0px) scale(0.9); opacity: 0; }
}

@keyframes swal2-animate-success-line-tip { 
  0% { top: 1.1875em; left: 0.0625em; width: 0px; }
  54% { top: 1.0625em; left: 0.125em; width: 0px; }
  70% { top: 2.1875em; left: -0.375em; width: 3.125em; }
  84% { top: 3em; left: 1.3125em; width: 1.0625em; }
  100% { top: 2.8125em; left: 0.8125em; width: 1.5625em; }
}

@keyframes swal2-animate-success-line-long { 
  0% { top: 3.375em; right: 2.875em; width: 0px; }
  65% { top: 3.375em; right: 2.875em; width: 0px; }
  84% { top: 2.1875em; right: 0px; width: 3.4375em; }
  100% { top: 2.375em; right: 0.5em; width: 2.9375em; }
}

@keyframes swal2-rotate-success-circular-line { 
  0% { transform: rotate(-45deg); }
  5% { transform: rotate(-45deg); }
  12% { transform: rotate(-405deg); }
  100% { transform: rotate(-405deg); }
}

@keyframes swal2-animate-error-x-mark { 
  0% { margin-top: 1.625em; transform: scale(0.4); opacity: 0; }
  50% { margin-top: 1.625em; transform: scale(0.4); opacity: 0; }
  80% { margin-top: -0.375em; transform: scale(1.15); }
  100% { margin-top: 0px; transform: scale(1); opacity: 1; }
}

@keyframes swal2-animate-error-icon { 
  0% { transform: rotateX(100deg); opacity: 0; }
  100% { transform: rotateX(0deg); opacity: 1; }
}

@keyframes swal2-rotate-loading { 
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

@keyframes swal2-animate-question-mark { 
  0% { transform: rotateY(-360deg); }
  100% { transform: rotateY(0deg); }
}

@keyframes swal2-animate-i-mark { 
  0% { transform: rotateZ(45deg); opacity: 0; }
  25% { transform: rotateZ(-25deg); opacity: 0.4; }
  50% { transform: rotateZ(15deg); opacity: 0.8; }
  75% { transform: rotateZ(-5deg); opacity: 1; }
  100% { transform: rotateX(0deg); opacity: 1; }
}

@keyframes swal2-toast-show { 
  0% { transform: translateY(-0.625em) rotateZ(2deg); }
  33% { transform: translateY(0px) rotateZ(-2deg); }
  66% { transform: translateY(0.3125em) rotateZ(2deg); }
  100% { transform: translateY(0px) rotateZ(0deg); }
}

@keyframes swal2-toast-hide { 
  100% { transform: rotateZ(1deg); opacity: 0; }
}

@keyframes swal2-toast-animate-success-line-tip { 
  0% { top: 0.5625em; left: 0.0625em; width: 0px; }
  54% { top: 0.125em; left: 0.125em; width: 0px; }
  70% { top: 0.625em; left: -0.25em; width: 1.625em; }
  84% { top: 1.0625em; left: 0.75em; width: 0.5em; }
  100% { top: 1.125em; left: 0.1875em; width: 0.75em; }
}

@keyframes swal2-toast-animate-success-line-long { 
  0% { top: 1.625em; right: 1.375em; width: 0px; }
  65% { top: 1.25em; right: 0.9375em; width: 0px; }
  84% { top: 0.9375em; right: 0px; width: 1.125em; }
  100% { top: 0.9375em; right: 0.1875em; width: 1.375em; }
}

@keyframes onetrust-fade-in { 
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes slide-down-custom { 
  0% { }
  100% { bottom: 0px; }
}

@-webkit-keyframes slide-down-custom { 
  0% { }
  100% { bottom: 0px; }
}

rules.cssText:
@supports (color:color-mix(in oklab,black,black)) {
  .btn-outline.btn-primary:hover { background-color: color-mix(in oklab,var(--fallback-p,oklch(var(--p)/1)) 90%,#000); border-color: color-mix(in oklab,var(--fallback-p,oklch(var(--p)/1)) 90%,#000); }
}

@supports (color:color-mix(in oklab,black,black)) {
  .btn-outline.btn-secondary:hover { background-color: color-mix(in oklab,var(--fallback-s,oklch(var(--s)/1)) 90%,#000); border-color: color-mix(in oklab,var(--fallback-s,oklch(var(--s)/1)) 90%,#000); }
}

@supports (color:color-mix(in oklab,black,black)) {
  .btn-outline.btn-accent:hover { background-color: color-mix(in oklab,var(--fallback-a,oklch(var(--a)/1)) 90%,#000); border-color: color-mix(in oklab,var(--fallback-a,oklch(var(--a)/1)) 90%,#000); }
}

@supports (color:color-mix(in oklab,black,black)) {
  .btn:is(input[type="checkbox"]:checked):hover, .btn:is(input[type="radio"]:checked):hover { background-color: color-mix(in oklab,var(--fallback-p,oklch(var(--p)/1)) 90%,#000); border-color: color-mix(in oklab,var(--fallback-p,oklch(var(--p)/1)) 90%,#000); }
}

@media (max-width: 767px) {
  #vtexIdUI-form-classic-login body.login { min-width: auto; }
  #vtexIdUI-form-classic-login body.login .footer, #vtexIdUI-form-classic-login body.login .header, #vtexIdUI-form-classic-login body.login .menu, #vtexIdUI-form-classic-login body.login .tipbar, #vtexIdUI-form-classic-login body.login .zEWidget-launcher { display: none; }
}

@media (max-width: 480px) {
  div.vtexIdUI { margin-left: 0px; top: 0px; left: 0px; transform: none; max-width: 100%; width: 100% !important; height: 100% !important; overflow: auto !important; }
}

@media (max-width: 479px) {
  div.vtexIdUI #changePswdBtn, div.vtexIdUI #tryChangePswdBtn { font-size: 0px; }
  div.vtexIdUI #changePswdBtn::after, div.vtexIdUI #tryChangePswdBtn::after { content: "Cadastrar"; font-size: 16px; }
}

@keyframes ripple { 
  0% { opacity: 0.3; transform: scaleZ(-1); }
  100% { opacity: 0; transform: scale3d(10, 10, -1); }
}

@keyframes shake-2 { 
  0% { }
  12.5% { transform: translateX(-50%) rotateY(-5deg); }
  37.5% { transform: translateX(-50%) rotateY(4deg); }
  62.5% { transform: translateX(-50%) rotateY(-2deg); }
  87.5% { transform: translateX(-50%) rotateY(1deg); }
  100% { transform: translateX(-50%); }
}

@media (max-width: 480px) {
  div.vtexIdUI { margin-left: 0px; top: 0px; left: 0px; transform: none; max-width: 100%; width: 100% !important; height: 100% !important; overflow: auto !important; }
}

@media (max-width: 479px) {
  div.vtexIdUI #changePswdBtn, div.vtexIdUI #tryChangePswdBtn { font-size: 0px; }
  div.vtexIdUI #changePswdBtn::after, div.vtexIdUI #tryChangePswdBtn::after { content: "Cadastrar"; font-size: 16px; }
}

@media screen and (max-width: 767px) {
  #vtexIdUI-form-classic-login body.login { min-width: auto; }
  #vtexIdUI-form-classic-login body.login .footer, #vtexIdUI-form-classic-login body.login .header, #vtexIdUI-form-classic-login body.login .menu, #vtexIdUI-form-classic-login body.login .tipbar, #vtexIdUI-form-classic-login body.login .zEWidget-launcher { display: none; }
}
